        }
        onCancel$={$(() => {
          store.style = "form";
        })}
        cancelLabel="Use form"
      />
    );
  }

  return (
    <AntiTabulaRasa
      mode="first-run"
      initialAnswers={null}
      onSubmit$={completeOnboarding$}
      onCancel$={onCancel$}
    />
  );
});

