          });

          if (error) {
            console.error("[twyne-auth] Resend error:", error);
            throw new Error("Failed to send verification email.");
          }
        },
      }),
      crossDomain({ siteUrl }),
      convex({ authConfig }),
    ],
  }) satisfies BetterAuthOptions;

